async delete(tableName: string, filter: string): Promise<void> {
    const table = await this.db.openTable(tableName)
    await table.delete(filter)
  }

static async create(dataDir: string): Promise<VectorStore> {
    const db = await lancedb.connect(dataDir)
    return new VectorStore(db)
  }

constructor(dbPath: string) {
    this.db = new Database(dbPath)
    this.db.pragma('journal_mode = WAL')
    this.db.pragma('synchronous = NORMAL')
    this.initTables()
  }

async close(): Promise<void> {
    // LanceDB Connection doesn't have an explicit close method;
    // dropping the reference is sufficient.
    this.db = null as unknown as lancedb.Connection
  }

getIntimacy(): number {
    const stmt = this.db.prepare('SELECT level FROM intimacy WHERE id = 1')
    const row = stmt.get() as { level: number }
    return row.level
  }

